  /**
   * 生成区块链验证哈希
   * @param {Object} certificate - 证书数据
   * @returns {Promise<string>} 哈希值
   */
  static async generateBlockchainHash(certificate) {
    try {
      // 使用证书数据生成哈希
      const dataToHash = `${certificate.certificateNumber}-${certificate.recipientName}-${certificate.program}-${certificate.issueDate}`;
      const hash = await sha256(dataToHash);
      return `SIU-${hash.substring(0, 16)}`;
    } catch (error) {
      console.error('生成区块链哈希失败:', error);
      // 返回备用哈希
      return `SIU-${Math.random().toString(36).substring(2, 10).toUpperCase()}`;
    }
  }

  /**
   * 添加验证用QR码
   * @param {jsPDF} doc - jsPDF文档对象 
   * @param {Object} certificate - 证书数据
   */
  static async addVerificationQR(doc, certificate) {
    // 获取页面尺寸
    const pageWidth = doc.internal.pageSize.getWidth();
    const pageHeight = doc.internal.pageSize.getHeight();
    try {
      // 构建验证URL
      const verifyUrl = `https://stratfordinternationaluniversity.edu/verify/${certificate.certificateNumber}`;

      // 使用qrcode库生成QR码的dataURL
      const qrDataURL = await QRCode.toDataURL(verifyUrl, {
        width: 80,
        margin: 1,
        color: {
          dark: '#000000',
          light: '#FFFFFF'
        }
      });

      // 将QR码添加到PDF
      doc.addImage(qrDataURL, 'PNG', pageWidth - 60, pageHeight - 85, 40, 40);

      // 添加扫描提示文本
      doc.setFontSize(8);
      doc.setTextColor(0, 48, 135);
      doc.setFont('helvetica', 'normal');
      doc.text('Scan to verify', pageWidth - 40, pageHeight - 35, {
        align: 'center'
      });

      // 添加验证信息到页面底部
      doc.setFontSize(10);
      doc.text(`Certificate Number: ${certificate.certificateNumber}`, pageWidth / 2, pageHeight - 30, {
        align: 'center'
      });
      doc.text(`Issue Date: ${new Date(certificate.issueDate).toLocaleDateString()}`, pageWidth / 2, pageHeight - 25, {
        align: 'center'
      });
      doc.text(`Blockchain Hash: ${certificate.blockchainHash}`, pageWidth / 2, pageHeight - 20, {
        align: 'center'
      });
      doc.text(`Verify at: https://stratfordinternationaluniversity.edu/verify/${certificate.certificateNumber}`, pageWidth / 2, pageHeight - 15, {
        align: 'center'
      });
    } catch (error) {
      console.error('生成QR码失败:', error);
      // 在QR码位置添加提示
      doc.setTextColor(255, 0, 0);
      doc.setFontSize(10);
      doc.text('QR Code\nUnavailable', pageWidth - 40, pageHeight - 60, {
        align: 'center'
      });
    }
  }

  /**
   * 添加签名图片
   * @param {jsPDF} doc - jsPDF文档对象
   * @param {Object} certificate - 证书数据
   */
  static async addSignatureImages(doc, certificate) {
    // 获取页面尺寸
    const pageWidth = doc.internal.pageSize.getWidth();
    const pageHeight = doc.internal.pageSize.getHeight();
    try {
      // 获取签名图片（在实际应用中，这些图片应该从存储中获取）
      const signature1Path = '/images/signatures/president.png';
      const signature2Path = '/images/signatures/director.png';

      // 签名位置参数
      const signatureY = pageHeight - 80;
      const signature1X = pageWidth / 3;
      const signature2X = pageWidth * 2 / 3;

      // 添加签名图片，如果图片加载失败，就画一条线
      try {
        // 第一个签名（校长）
        const baseUrl = window.location.origin;
        const signature1Url = `${baseUrl}${signature1Path}`;
        doc.addImage(signature1Url, 'PNG', signature1X - 30, signatureY - 15, 60, 20);
      } catch (error) {
        // 如果图片加载失败，画一条线作为替代
        doc.setDrawColor(0, 0, 0);
        doc.line(signature1X - 30, signatureY, signature1X + 30, signatureY);
      }
      try {
        // 第二个签名（主任）
        const baseUrl = window.location.origin;
        const signature2Url = `${baseUrl}${signature2Path}`;
        doc.addImage(signature2Url, 'PNG', signature2X - 30, signatureY - 15, 60, 20);
      } catch (error) {
        // 如果图片加载失败，画一条线作为替代
        doc.setDrawColor(0, 0, 0);
        doc.line(signature2X - 30, signatureY, signature2X + 30, signatureY);
      }

      // 添加签名人姓名和职位
      doc.setFontSize(12);
      doc.setFont('helvetica', 'bold');
      doc.setTextColor(0, 0, 0);
      doc.text('Dr. Elizabeth Stratford', signature1X, signatureY + 10, {
        align: 'center'
      });
      doc.text('Prof. Michael Abide', signature2X, signatureY + 10, {
        align: 'center'
      });
      doc.setFontSize(8);
      doc.setFont('helvetica', 'normal');
      doc.text('University President', signature1X, signatureY + 15, {
        align: 'center'
      });
      doc.text('Program Director', signature2X, signatureY + 15, {
        align: 'center'
      });
    } catch (error) {
      console.error('添加签名图片失败:', error);
    }
  }

  /**
   * 添加装饰元素到证书
   * @param {jsPDF} doc - jsPDF文档对象
   */
  static addDecorativeElements(doc) {
    // 获取页面尺寸
    const pageWidth = doc.internal.pageSize.getWidth();
    const pageHeight = doc.internal.pageSize.getHeight();

    // 绘制金色边框
    doc.setDrawColor(212, 160, 23); // 金色 #D4A017
