    // 绘制内边框
    doc.setLineWidth(0.5);
    doc.rect(15, 15, pageWidth - 30, pageHeight - 30);

    // 添加装饰角
    // 左上角
    doc.setFillColor(212, 160, 23);
    doc.triangle(10, 10, 25, 10, 10, 25, 'F');

    // 右上角
    doc.triangle(pageWidth - 10, 10, pageWidth - 25, 10, pageWidth - 10, 25, 'F');

    // 左下角
    doc.triangle(10, pageHeight - 10, 25, pageHeight - 10, 10, pageHeight - 25, 'F');

    // 右下角
    doc.triangle(pageWidth - 10, pageHeight - 10, pageWidth - 25, pageHeight - 10, pageWidth - 10, pageHeight - 25, 'F');

    // 添加装饰缎带
    doc.setFillColor(0, 48, 135); // 深蓝色 #003087
    doc.saveGraphicsState();
    doc.translate(pageWidth - 40, 40);
    doc.rotate(45);
    doc.rect(-10, -5, 80, 10, 'F');
    doc.restoreGraphicsState();

    // 添加学校印章
    doc.setDrawColor(0, 48, 135); // 深蓝色
    doc.setLineWidth(1);
    doc.circle(pageWidth / 2, pageHeight - 80, 20);
    doc.setLineWidth(0.5);
    doc.circle(pageWidth / 2, pageHeight - 80, 18);
    doc.setFontSize(8);
    doc.setTextColor(0, 48, 135);
