      align: 'center'
    });
    doc.text('INTERNATIONAL', pageWidth / 2, pageHeight - 80, {
      align: 'center'
    });
    doc.text('UNIVERSITY', pageWidth / 2, pageHeight - 75, {
      align: 'center'
    });

    // 添加区块链验证图标
    const iconX = 40;
    const iconY = pageHeight - 75;

    // 绘制简化的区块链图标
    doc.setFillColor(0, 48, 135);
